//! Arnold cat-map route planner for diffusion-style shadow paths.
//!
//! This mirrors `Gnosis.CatMapDiffusionRoute`: cat maps are finite reversible
//! route families, not contraction proofs.  Runtime promotion out of shadow mode
//! requires explicit evidence: no energy increase, no topology-depth regression,
//! and a verified fingerprint.

pub const CAT_MAP_DIFFUSION_ROUTE_THEOREM_IDS: [&str; 6] = [
    "Gnosis.CatMapDiffusionRoute.certified_routes_return_at_period",
    "Gnosis.CatMapDiffusionRoute.routePoint_stays_in_carrier",
    "Gnosis.CatMapDiffusionRoute.route_return_no_strict_descent",
    "Gnosis.CatMapDiffusionRoute.routeAccepted_implies_energy_nonincrease",
    "Gnosis.CatMapDiffusionRoute.routeAccepted_implies_topology_nonregression",
    "Gnosis.CatMapDiffusionRoute.slideDown_le_start",
];

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum CertifiedCatRoute {
    Mod2,
    Mod3,
    Mod5,
}

impl CertifiedCatRoute {
    pub const fn modulus(self) -> u32 {
        match self {
            Self::Mod2 => 2,
            Self::Mod3 => 3,
            Self::Mod5 => 5,
        }
    }

    pub const fn period(self) -> u32 {
        match self {
            Self::Mod2 => 3,
            Self::Mod3 => 4,
            Self::Mod5 => 10,
        }
    }
}

pub const CERTIFIED_CAT_ROUTE_CATALOG: [CertifiedCatRoute; 3] = [
    CertifiedCatRoute::Mod2,
    CertifiedCatRoute::Mod3,
    CertifiedCatRoute::Mod5,
];

#[derive(Clone, Copy, Debug, Default, PartialEq, Eq)]
pub struct TorusPoint {
    pub x: u32,
    pub y: u32,
}

impl TorusPoint {
    pub const fn new(x: u32, y: u32) -> Self {
        Self { x, y }
    }

    pub const fn index(self, modulus: u32) -> usize {
        (self.x * modulus + self.y) as usize
    }
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum CatMapRouteError {
    ZeroModulus,
    RowWidthZero,
    InputLengthMismatch,
    PointOutsideCarrier,
}

pub fn cat_map_point(modulus: u32, point: TorusPoint) -> Result<TorusPoint, CatMapRouteError> {
    if modulus == 0 {
        return Err(CatMapRouteError::ZeroModulus);
    }
    Ok(TorusPoint {
        x: (2 * point.x + point.y) % modulus,
        y: (point.x + point.y) % modulus,
    })
}

pub fn cat_map_iter(
    modulus: u32,
    ticks: u32,
    mut point: TorusPoint,
) -> Result<TorusPoint, CatMapRouteError> {
    if modulus == 0 {
        return Err(CatMapRouteError::ZeroModulus);
    }
    point.x %= modulus;
    point.y %= modulus;
    for _ in 0..ticks {
        point = cat_map_point(modulus, point)?;
    }
    Ok(point)
}

pub fn certified_route_point(
    route: CertifiedCatRoute,
    ticks: u32,
    point: TorusPoint,
) -> TorusPoint {
    cat_map_iter(route.modulus(), ticks, point).expect("certified route modulus is always positive")
}

pub fn certified_route_returns_at_period(route: CertifiedCatRoute) -> bool {
    let modulus = route.modulus();
    for x in 0..modulus {
        for y in 0..modulus {
            let point = TorusPoint::new(x, y);
            if certified_route_point(route, route.period(), point) != point {
                return false;
            }
        }
    }
    true
}

/// Precompute the finite permutation induced by a route/tick pair.  Entries
/// are row-major source index -> row-major destination index.
pub fn cat_map_permutation(
    route: CertifiedCatRoute,
    ticks: u32,
) -> Result<Vec<usize>, CatMapRouteError> {
    cat_map_permutation_modulus(route.modulus(), ticks)
}

/// Precompute the finite permutation induced by an arbitrary cat-map modulus.
///
/// This is the exploratory runtime counterpart to the small certified catalog:
/// callers may use it for image-size torus routes, but admission to a theorem
/// gate should still cite a certified route or a separately checked proof.
pub fn cat_map_permutation_modulus(
    modulus: u32,
    ticks: u32,
) -> Result<Vec<usize>, CatMapRouteError> {
    if modulus == 0 {
        return Err(CatMapRouteError::ZeroModulus);
    }
    let mut permutation = Vec::with_capacity((modulus * modulus) as usize);
    for x in 0..modulus {
        for y in 0..modulus {
            let dst = cat_map_iter(modulus, ticks, TorusPoint::new(x, y))?;
            permutation.push(dst.index(modulus));
        }
    }
    Ok(permutation)
}

pub fn cat_map_period_modulus(
    modulus: u32,
    max_ticks: u32,
) -> Result<Option<u32>, CatMapRouteError> {
    if modulus == 0 {
        return Err(CatMapRouteError::ZeroModulus);
    }
    for ticks in 1..=max_ticks {
        let mut is_identity = true;
        for x in 0..modulus {
            for y in 0..modulus {
                let point = TorusPoint::new(x, y);
                if cat_map_iter(modulus, ticks, point)? != point {
                    is_identity = false;
                    break;
                }
            }
            if !is_identity {
                break;
            }
        }
        if is_identity {
            return Ok(Some(ticks));
        }
    }
    Ok(None)
}

/// Number of row-major route slots covered by a certified cat-map carrier.
pub const fn route_carrier_rows(route: CertifiedCatRoute) -> usize {
    let modulus = route.modulus() as usize;
    modulus * modulus
}

/// Apply a cat-map route to the first `modulus^2` rows of a row-major tensor.
///
/// Rows outside the finite carrier are copied unchanged. This lets a 5x5 route
/// cover the hot prefix of a 30-step action trajectory while preserving the
/// remaining steps as canonical tail context.
pub fn route_row_prefix_f32(
    input: &[f32],
    row_width: usize,
    route: CertifiedCatRoute,
    ticks: u32,
) -> Result<Vec<f32>, CatMapRouteError> {
    if row_width == 0 {
        return Err(CatMapRouteError::RowWidthZero);
    }
    if !input.len().is_multiple_of(row_width) {
        return Err(CatMapRouteError::InputLengthMismatch);
    }
    let rows = input.len() / row_width;
    let carrier_rows = route_carrier_rows(route);
    if rows < carrier_rows {
        return Err(CatMapRouteError::PointOutsideCarrier);
    }

    let permutation = cat_map_permutation(route, ticks)?;
    let mut output = input.to_vec();
    for (src, dst) in permutation.iter().copied().enumerate() {
        let src_lo = src * row_width;
        let dst_lo = dst * row_width;
        output[dst_lo..dst_lo + row_width].copy_from_slice(&input[src_lo..src_lo + row_width]);
    }
    Ok(output)
}

/// Undo [`route_row_prefix_f32`] for the same route/tick pair.
pub fn unroute_row_prefix_f32(
    routed: &[f32],
    row_width: usize,
    route: CertifiedCatRoute,
    ticks: u32,
) -> Result<Vec<f32>, CatMapRouteError> {
    if row_width == 0 {
        return Err(CatMapRouteError::RowWidthZero);
    }
    if !routed.len().is_multiple_of(row_width) {
        return Err(CatMapRouteError::InputLengthMismatch);
    }
    let rows = routed.len() / row_width;
    let carrier_rows = route_carrier_rows(route);
    if rows < carrier_rows {
        return Err(CatMapRouteError::PointOutsideCarrier);
    }

    let permutation = cat_map_permutation(route, ticks)?;
    let mut output = routed.to_vec();
    for (src, dst) in permutation.iter().copied().enumerate() {
        let src_lo = src * row_width;
        let dst_lo = dst * row_width;
        output[src_lo..src_lo + row_width].copy_from_slice(&routed[dst_lo..dst_lo + row_width]);
    }
    Ok(output)
}

/// Apply a cat-map route to an `n x n` row-major tensor with `channels` values
/// per point. This is intended for image/latent probes where the full square
/// lattice is the route carrier.
pub fn route_square_grid_f32(
    input: &[f32],
    channels: usize,
    modulus: u32,
    ticks: u32,
) -> Result<Vec<f32>, CatMapRouteError> {
    if channels == 0 {
        return Err(CatMapRouteError::RowWidthZero);
    }
    let side = modulus as usize;
    if side == 0 {
        return Err(CatMapRouteError::ZeroModulus);
    }
    if input.len() != side * side * channels {
        return Err(CatMapRouteError::InputLengthMismatch);
    }

    let permutation = cat_map_permutation_modulus(modulus, ticks)?;
    let mut output = input.to_vec();
    for (src, dst) in permutation.iter().copied().enumerate() {
        let src_lo = src * channels;
        let dst_lo = dst * channels;
        output[dst_lo..dst_lo + channels].copy_from_slice(&input[src_lo..src_lo + channels]);
    }
    Ok(output)
}

/// Undo [`route_square_grid_f32`] for the same modulus/tick pair.
pub fn unroute_square_grid_f32(
    routed: &[f32],
    channels: usize,
    modulus: u32,
    ticks: u32,
) -> Result<Vec<f32>, CatMapRouteError> {
    if channels == 0 {
        return Err(CatMapRouteError::RowWidthZero);
    }
    let side = modulus as usize;
    if side == 0 {
        return Err(CatMapRouteError::ZeroModulus);
    }
    if routed.len() != side * side * channels {
        return Err(CatMapRouteError::InputLengthMismatch);
    }

    let permutation = cat_map_permutation_modulus(modulus, ticks)?;
    let mut output = routed.to_vec();
    for (src, dst) in permutation.iter().copied().enumerate() {
        let src_lo = src * channels;
        let dst_lo = dst * channels;
        output[src_lo..src_lo + channels].copy_from_slice(&routed[dst_lo..dst_lo + channels]);
    }
    Ok(output)
}

/// Quantized L2 energy for telemetry and theorem-gated admission.
pub fn quantized_l2_energy(values: &[f32]) -> u64 {
    let mut sum = 0.0f64;
    for &value in values {
        if value.is_finite() {
            let v = value as f64;
            sum += v * v;
        } else {
            return u64::MAX;
        }
    }
    if !sum.is_finite() || sum >= (u64::MAX as f64 / 1_000_000.0) {
        u64::MAX
    } else {
        (sum * 1_000_000.0).round() as u64
    }
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct CatMapRouteEvidence {
    pub canonical_energy: u64,
    pub routed_energy: u64,
    /// Topological depth/coherence class, expected in `0..=7`.
    pub topology_before: u8,
    /// Topological depth/coherence class, expected in `0..=7`.
    pub topology_after: u8,
    pub fingerprint_verified: bool,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum CatMapRouteRejectReason {
    EnergyIncreased,
    TopologyRegressed,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum CatMapRouteAdmission {
    Admitted {
        theorem_ids: &'static [&'static str],
    },
    ShadowOnly {
        theorem_ids: &'static [&'static str],
    },
    Rejected {
        reason: CatMapRouteRejectReason,
        theorem_ids: &'static [&'static str],
    },
}

pub fn admit_cat_map_route(evidence: CatMapRouteEvidence) -> CatMapRouteAdmission {
    if !evidence.fingerprint_verified {
        return CatMapRouteAdmission::ShadowOnly {
            theorem_ids: &CAT_MAP_DIFFUSION_ROUTE_THEOREM_IDS,
        };
    }
    if evidence.routed_energy > evidence.canonical_energy {
        return CatMapRouteAdmission::Rejected {
            reason: CatMapRouteRejectReason::EnergyIncreased,
            theorem_ids: &CAT_MAP_DIFFUSION_ROUTE_THEOREM_IDS,
        };
    }
    if evidence.topology_after < evidence.topology_before {
        return CatMapRouteAdmission::Rejected {
            reason: CatMapRouteRejectReason::TopologyRegressed,
            theorem_ids: &CAT_MAP_DIFFUSION_ROUTE_THEOREM_IDS,
        };
    }
    CatMapRouteAdmission::Admitted {
        theorem_ids: &CAT_MAP_DIFFUSION_ROUTE_THEOREM_IDS,
    }
}

pub const fn accept_energy(current: u64, proposed: u64) -> u64 {
    if proposed <= current {
        proposed
    } else {
        current
    }
}

pub fn slide_down_energies(start: u64, proposals: &[u64]) -> u64 {
    let mut current = start;
    for proposed in proposals {
        current = accept_energy(current, *proposed);
    }
    current
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn certified_routes_return_on_period() {
        for route in CERTIFIED_CAT_ROUTE_CATALOG {
            assert!(certified_route_returns_at_period(route));
        }
    }

    #[test]
    fn mod5_nine_plus_one_returns_seed() {
        let seed = TorusPoint::new(1, 0);
        let scrambled = certified_route_point(CertifiedCatRoute::Mod5, 9, seed);
        assert_eq!(scrambled, TorusPoint::new(1, 4));
        let recovered = certified_route_point(CertifiedCatRoute::Mod5, 1, scrambled);
        assert_eq!(recovered, seed);
    }

    #[test]
    fn cat_map_permutation_is_bijective_on_mod5_carrier() {
        let mut permutation = cat_map_permutation(CertifiedCatRoute::Mod5, 9).unwrap();
        assert_eq!(permutation.len(), 25);
        permutation.sort_unstable();
        permutation.dedup();
        assert_eq!(permutation.len(), 25);
        assert_eq!(permutation[0], 0);
        assert_eq!(permutation[24], 24);
    }

    #[test]
    fn arbitrary_modulus_period_discovery_matches_certified_catalog() {
        assert_eq!(cat_map_period_modulus(2, 32).unwrap(), Some(3));
        assert_eq!(cat_map_period_modulus(3, 32).unwrap(), Some(4));
        assert_eq!(cat_map_period_modulus(5, 32).unwrap(), Some(10));
    }

    #[test]
    fn square_grid_route_roundtrips_multi_channel_image() {
        let side = 8u32;
        let channels = 4;
        let input: Vec<f32> = (0..side as usize * side as usize * channels)
            .map(|v| (v as f32 * 0.125).sin())
            .collect();
        let routed = route_square_grid_f32(&input, channels, side, 5).unwrap();
        let recovered = unroute_square_grid_f32(&routed, channels, side, 5).unwrap();
        assert_eq!(recovered, input);
    }

    #[test]
    fn route_row_prefix_roundtrips_and_preserves_tail() {
        let rows = 30;
        let row_width = 3;
        let input: Vec<f32> = (0..rows * row_width).map(|v| v as f32).collect();
        let routed = route_row_prefix_f32(&input, row_width, CertifiedCatRoute::Mod5, 7).unwrap();
        let recovered =
            unroute_row_prefix_f32(&routed, row_width, CertifiedCatRoute::Mod5, 7).unwrap();
        assert_eq!(recovered, input);
        assert_eq!(routed[25 * row_width..], input[25 * row_width..]);
    }

    #[test]
    fn quantized_energy_rejects_nonfinite_values() {
        assert_eq!(quantized_l2_energy(&[3.0, 4.0]), 25_000_000);
        assert_eq!(quantized_l2_energy(&[f32::NAN]), u64::MAX);
    }

    #[test]
    fn route_admission_requires_shadow_validation_then_gates() {
        let base = CatMapRouteEvidence {
            canonical_energy: 100,
            routed_energy: 90,
            topology_before: 4,
            topology_after: 5,
            fingerprint_verified: false,
        };
        assert!(matches!(
            admit_cat_map_route(base),
            CatMapRouteAdmission::ShadowOnly { .. }
        ));

        assert!(matches!(
            admit_cat_map_route(CatMapRouteEvidence {
                fingerprint_verified: true,
                ..base
            }),
            CatMapRouteAdmission::Admitted { .. }
        ));

        assert!(matches!(
            admit_cat_map_route(CatMapRouteEvidence {
                routed_energy: 101,
                fingerprint_verified: true,
                ..base
            }),
            CatMapRouteAdmission::Rejected {
                reason: CatMapRouteRejectReason::EnergyIncreased,
                ..
            }
        ));

        assert!(matches!(
            admit_cat_map_route(CatMapRouteEvidence {
                topology_after: 3,
                fingerprint_verified: true,
                ..base
            }),
            CatMapRouteAdmission::Rejected {
                reason: CatMapRouteRejectReason::TopologyRegressed,
                ..
            }
        ));
    }

    #[test]
    fn accepted_energy_descent_is_monotone() {
        assert_eq!(slide_down_energies(100, &[99, 120, 80, 81, 79]), 79);
        assert!(slide_down_energies(100, &[101, 120, 100]) <= 100);
    }
}
